const configs = $input.first().json.data || [];
return configs
  .filter(c => c.qc_project_id)
  .map(c => ({ json: { qc_project_id: c.qc_project_id, tuleap_tracker_id: c.tuleap_tracker_id } }));

const projectId = $('Split Configs').first().json.qc_project_id;
const items = ($input.first().json.data || []);
return items.map(artifact => ({
  json: { artifact, project_id: projectId }
}));

const { artifact, project_id } = $input.first().json;
const fields = {};
for (const v of (artifact.values || [])) { fields[v.name] = v; }

function txt(...names) {
  for (const n of names) { const f = fields[n]; if (f && f.value != null) return String(f.value); } return null;
}
function sel(...names) {
  for (const n of names) { const f = fields[n]; if (f?.values?.[0]) return f.values[0].label || null; } return null;
}
function user(...names) {
  for (const n of names) { const f = fields[n]; if (f?.values?.[0]) return f.values[0].display_name || f.values[0].username || null; } return null;
}
function mapStatus(s) {
  if (!s) return 'Open';
  return { New:'Open', Open:'Open', Assigned:'In Progress', Fixed:'Resolved', Verified:'Resolved', Closed:'Closed', Reopened:'Reopened' }[s] || 'Open';
}
function mapSeverity(s) {
  if (!s) return 'medium';
  const l = s.toLowerCase();
  if (l.includes('critical')) return 'critical';
  if (l.includes('major'))    return 'high';
  if (l.includes('minor'))    return 'medium';
  if (l.includes('cosmetic')) return 'low';
  return 'medium';
}

return [{ json: { bugData: {
  tuleap_artifact_id: artifact.id,
  tuleap_tracker_id: artifact.tracker?.id,
  bug_id: `TLP-${artifact.id}`,
  title: txt('bug_title') || `Bug ${artifact.id}`,
  description: txt('steps_to_reproduce'),
  status: mapStatus(sel('status')),
  severity: mapSeverity(sel('severity')),
  priority: 'medium',
  project_id,
  assigned_to: user('assigned_to'),
  reported_date: artifact.submitted_on || null,
  raw_tuleap_payload: artifact
} } }];
